path = r"d:\практика 2025\bmp2svga_serv\start_site.bat"

content = "@echo off\r\nsetlocal EnableExtensions EnableDelayedExpansion\r\nchcp 65001 >nul\r\n\r\ncd /d \"%~dp0\"\r\nset \"ROOT=%CD%\"\r\n\r\necho ===============================================\r\necho  BMP2SVG startup\r\necho  Root: %ROOT%\r\necho ===============================================\r\necho.\r\n\r\nset \"API_HOST=127.0.0.1\"\r\nset \"API_PORT=8000\"\r\nset \"FRONT_PORT=8080\"\r\nset \"DATABASE_URL=postgresql://bmp2svg:bmp2svg@127.0.0.1:5432/bmp2svg\"\r\nset \"REDIS_URL=redis://127.0.0.1:6379/0\"\r\nset \"BMP2SVG_STATE_USE_REDIS=1\"\r\nset \"BMP2SVG_QUEUE_NAME=bmp2svg-jobs\"\r\nset \"BMP2SVG_JOB_MAX_RETRIES=2\"\r\nset \"BMP2SVG_STUCK_JOB_SEC=600\"\r\nset \"OLLAMA_URL=http://localhost:11434\"\r\nset \"OLLAMA_MODEL=gpt-oss:20b\"\r\nset \"OLLAMA_TIMEOUT_SEC=120\"\r\n\r\nif not exist \".env\" (\r\n    if exist \".env.example\" copy /Y \".env.example\" \".env\" >nul\r\n)\r\nif exist \".env\" (\r\n    for /f \"usebackq tokens=1,* delims==\" %%A in (\".env\") do (\r\n        set \"L=%%A\"\r\n        if not \"!L:~0,1!\"==\"#\" if not \"%%A\"==\"\" if not \"%%B\"==\"\" set \"%%A=%%B\"\r\n    )\r\n)\r\n\r\necho [check] python...\r\nwhere python >nul 2>nul\r\nif errorlevel 1 ( echo [ERROR] python not found! & goto :fail )\r\n\r\necho [check] docker...\r\nwhere docker >nul 2>nul\r\nif errorlevel 1 ( echo [ERROR] docker not found! & goto :fail )\r\n\r\necho.\r\necho [1/8] Docker...\r\ndocker info >nul 2>nul\r\nif errorlevel 1 (\r\n    echo Starting Docker Desktop...\r\n    if exist \"C:\\Program Files\\Docker\\Docker\\Docker Desktop.exe\" (\r\n        start \"\" \"C:\\Program Files\\Docker\\Docker\\Docker Desktop.exe\"\r\n    ) else (\r\n        echo [ERROR] Docker Desktop not found.\r\n        goto :fail\r\n    )\r\n    echo Waiting for Docker...\r\n    set /a \"CNT=0\"\r\n    :wait_docker\r\n    timeout /t 3 /nobreak >nul\r\n    docker info >nul 2>nul\r\n    if not errorlevel 1 goto :docker_ok\r\n    set /a \"CNT+=1\"\r\n    if !CNT! lss 30 goto :wait_docker\r\n    echo [ERROR] Docker did not start.\r\n    goto :fail\r\n)\r\n:docker_ok\r\necho [ok] Docker running.\r\n\r\ndocker compose up -d postgres redis\r\nif errorlevel 1 ( echo [ERROR] docker compose failed & goto :fail )\r\n\r\necho Waiting for postgres...\r\nset /a \"CNT=0\"\r\n:wait_pg\r\ntimeout /t 2 /nobreak >nul\r\nset \"ST=\"\r\nfor /f %%S in ('docker inspect -f \"{{.State.Health.Status}}\" bmp2svg-postgres 2^>nul') do set \"ST=%%S\"\r\nif /i \"!ST!\"==\"healthy\" goto :pg_ok\r\nif /i \"!ST!\"==\"unhealthy\" ( echo [ERROR] postgres unhealthy & goto :fail )\r\nset /a \"CNT+=1\"\r\nif !CNT! lss 45 goto :wait_pg\r\necho [ERROR] postgres timeout\r\ngoto :fail\r\n:pg_ok\r\necho [ok] postgres ready.\r\n\r\necho Waiting for redis...\r\nset /a \"CNT=0\"\r\n:wait_redis\r\ntimeout /t 2 /nobreak >nul\r\nset \"ST=\"\r\nfor /f %%S in ('docker inspect -f \"{{.State.Health.Status}}\" bmp2svg-redis 2^>nul') do set \"ST=%%S\"\r\nif /i \"!ST!\"==\"healthy\" goto :redis_ok\r\nif /i \"!ST!\"==\"unhealthy\" ( echo [ERROR] redis unhealthy & goto :fail )\r\nset /a \"CNT+=1\"\r\nif !CNT! lss 45 goto :wait_redis\r\necho [ERROR] redis timeout\r\ngoto :fail\r\n:redis_ok\r\necho [ok] redis ready.\r\n\r\necho.\r\necho [2/8] pip install...\r\npython -m pip install -r requirements.txt -q\r\nif errorlevel 1 ( echo [ERROR] pip install failed & goto :fail )\r\necho [ok] dependencies ok.\r\n\r\necho.\r\necho [3/8] alembic upgrade...\r\npython -m alembic -c alembic.ini upgrade head\r\nif errorlevel 1 ( echo [ERROR] alembic migration failed & goto :fail )\r\necho [ok] migrations ok.\r\n\r\necho.\r\necho [4/8] Ollama check...\r\nnetstat -ano | findstr /R /C:\":11434 .*LISTENING\" >nul 2>nul\r\nif not errorlevel 1 (\r\n    echo [ok] Ollama already running.\r\n    goto :ollama_done\r\n)\r\nwhere ollama >nul 2>nul\r\nif errorlevel 1 (\r\n    echo [warn] ollama not found. AI disabled.\r\n    goto :ollama_done\r\n)\r\necho Starting ollama...\r\nstart \"BMP2SVG Ollama\" cmd /c \"ollama serve\"\r\nset /a \"CNT=0\"\r\n:wait_ollama\r\ntimeout /t 2 /nobreak >nul\r\nnetstat -ano | findstr /R /C:\":11434 .*LISTENING\" >nul 2>nul\r\nif not errorlevel 1 ( echo [ok] Ollama started. & goto :ollama_done )\r\nset /a \"CNT+=1\"\r\nif !CNT! lss 15 goto :wait_ollama\r\necho [warn] Ollama timeout. AI may not work.\r\n:ollama_done\r\n\r\necho.\r\necho [5/8] Picking ports...\r\ncall :pick_port API_PORT %API_PORT%\r\ncall :pick_port FRONT_PORT %FRONT_PORT%\r\necho [ok] API=%API_PORT%  Frontend=%FRONT_PORT%\r\n\r\necho.\r\necho [6/8] Starting API on port %API_PORT%...\r\nset \"CMD_API=Set-Location '%ROOT%'; $env:DATABASE_URL='%DATABASE_URL%'; $env:REDIS_URL='%REDIS_URL%'; $env:BMP2SVG_STATE_USE_REDIS='%BMP2SVG_STATE_USE_REDIS%'; $env:BMP2SVG_QUEUE_NAME='%BMP2SVG_QUEUE_NAME%'; $env:BMP2SVG_JOB_MAX_RETRIES='%BMP2SVG_JOB_MAX_RETRIES%'; $env:BMP2SVG_STUCK_JOB_SEC='%BMP2SVG_STUCK_JOB_SEC%'; $env:OLLAMA_URL='%OLLAMA_URL%'; $env:OLLAMA_MODEL='%OLLAMA_MODEL%'; $env:OLLAMA_TIMEOUT_SEC='%OLLAMA_TIMEOUT_SEC%'; python -m uvicorn backend.main:app --host %API_HOST% --port %API_PORT%\"\r\nstart \"BMP2SVG API\" powershell -NoExit -ExecutionPolicy Bypass -Command \"%CMD_API%\"\r\n\r\necho [7/8] Starting Worker...\r\nset \"CMD_WRK=Set-Location '%ROOT%'; $env:DATABASE_URL='%DATABASE_URL%'; $env:REDIS_URL='%REDIS_URL%'; $env:BMP2SVG_STATE_USE_REDIS='%BMP2SVG_STATE_USE_REDIS%'; $env:BMP2SVG_QUEUE_NAME='%BMP2SVG_QUEUE_NAME%'; $env:BMP2SVG_JOB_MAX_RETRIES='%BMP2SVG_JOB_MAX_RETRIES%'; $env:BMP2SVG_STUCK_JOB_SEC='%BMP2SVG_STUCK_JOB_SEC%'; python -m backend.worker\"\r\nstart \"BMP2SVG Worker\" powershell -NoExit -ExecutionPolicy Bypass -Command \"%CMD_WRK%\"\r\n\r\necho [8/8] Starting Frontend on port %FRONT_PORT%...\r\nstart \"BMP2SVG Frontend\" powershell -NoExit -ExecutionPolicy Bypass -Command \"Set-Location '%ROOT%'; python -m http.server %FRONT_PORT% --directory frontend\"\r\n\r\necho.\r\necho Waiting for API...\r\nset /a \"CNT=0\"\r\n:wait_api\r\ntimeout /t 2 /nobreak >nul\r\nnetstat -ano | findstr /R /C:\":%API_PORT% .*LISTENING\" >nul 2>nul\r\nif not errorlevel 1 goto :api_ready\r\nset /a \"CNT+=1\"\r\nif !CNT! lss 20 goto :wait_api\r\necho [warn] API not responding. Check terminal BMP2SVG API.\r\ngoto :show_urls\r\n:api_ready\r\necho [ok] API ready.\r\n\r\n:show_urls\r\necho.\r\necho ===============================================\r\necho  Project started!\r\necho.\r\necho  API:       http://%API_HOST%:%API_PORT%\r\necho  Docs:      http://%API_HOST%:%API_PORT%/docs\r\necho  Frontend:  http://%API_HOST%:%FRONT_PORT%/index.html\r\necho ===============================================\r\necho.\r\nstart \"\" \"http://%API_HOST%:%FRONT_PORT%/index.html\"\r\necho Keep the opened terminals running.\r\necho.\r\necho Press any key to close this window...\r\npause >nul\r\nexit /b 0\r\n\r\n:fail\r\necho.\r\necho *** STARTUP FAILED ***\r\necho.\r\necho Press any key to close...\r\npause >nul\r\nexit /b 1\r\n\r\n:pick_port\r\nset /a \"P=%~2\"\r\n:_pp\r\nnetstat -ano | findstr /R /C:\":%P% .*LISTENING\" >nul 2>nul\r\nif not errorlevel 1 ( set /a \"P+=1\" & goto :_pp )\r\nset \"%~1=%P%\"\r\nexit /b 0\r\n"

with open(path, 'wb') as f:
    f.write(content.encode('ascii'))

# Verify
with open(path, 'rb') as f:
    data = f.read()
print(f"File written: {len(data)} bytes")
print(f"Lines: {data.count(b'\r\n')}")
print("First 100 chars:", data[:100])
print("Last 100 chars:", data[-100:])
